#!/usr/bin/env python3
import json
from pathlib import Path
ROOT=Path(__file__).resolve().parents[1]; DATA=ROOT/'data'; SITE=ROOT/'site'
def money(c): return ('-' if c<0 else '')+'$'+format(abs(c)/100,'.2f')
def main():
    SITE.mkdir(parents=True,exist_ok=True)
    snap=json.loads((DATA/'market_snapshot.json').read_text()); brief=json.loads((DATA/'brief.json').read_text()); ledger=json.loads((DATA/'ledger.json').read_text())
    (SITE/'data.json').write_text(json.dumps({'snapshot':snap,'brief':brief,'ledger':ledger,'format':{'balance':money(ledger['balance_cents']),'price':money(ledger['price_cents'])}},indent=2))
    (SITE/'index.html').write_text(INDEX); (SITE/'styles.css').write_text(STYLES); (SITE/'app.js').write_text(APP)
    print(json.dumps({'ok':True,'site':str(SITE/'index.html'),'data':str(SITE/'data.json')},indent=2))
INDEX = """<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Otto Margin Desk</title><link rel="stylesheet" href="styles.css"></head><body><header class="topbar"><div><p class="eyebrow">Hermes Agent Accelerated Business Hackathon</p><h1>Otto Margin Desk</h1></div><div class="status-pill" id="paymentMode">loading</div></header><main><section class="hero card"><div><p class="eyebrow">Agent-run business loop</p><h2 id="headline">Loading brief...</h2><p id="abstract" class="lede"></p><div class="cta-row"><button id="buyButton">Buy today's brief - $3</button><button class="secondary" id="runButton">Run next scout cycle</button></div></div><div class="hero-metrics"><div><span id="price">--</span><label>Brief price</label></div><div><span id="balance">--</span><label>Treasury after reinvest</label></div><div><span id="confidence">--</span><label>MoA confidence</label></div></div></section><section class="grid three"><article class="card"><p class="eyebrow">1 / Scout</p><h3>Public signals</h3><p>FRED economic series plus X/social market context become an restaurant margin snapshot.</p></article><article class="card"><p class="eyebrow">2 / Synthesize</p><h3>MoA council</h3><p>GPT-5.5 reference plus GLM 5.2 reference feed a GPT-5.5 aggregator.</p></article><article class="card"><p class="eyebrow">3 / Operate</p><h3>Sell, deliver, reinvest</h3><p>Checkout event creates revenue, ledger allocates costs, delivery payload is prepared.</p></article></section><section class="card"><div class="section-head"><div><p class="eyebrow">Paid intelligence</p><h2>Signals ranked by margin relevance</h2></div><span id="generatedAt" class="muted"></span></div><div id="signals" class="signals"></div></section><section class="grid two"><article class="card"><p class="eyebrow">Today's play</p><h2>What the margin leader should do</h2><ol id="operatorPlay"></ol></article><article class="card"><p class="eyebrow">MoA roles</p><h2>Corrected council setup</h2><div id="moaRoles" class="roles"></div></article></section><section class="grid two"><article class="card"><p class="eyebrow">Treasury</p><h2>Revenue and spend ledger</h2><div id="ledger" class="ledger"></div></article><article class="card"><p class="eyebrow">Controls</p><h2>Safety limits</h2><div id="safety" class="safety"></div><p class="small">Live spending is blocked unless a human approves it. Missing Stripe test keys fall back to a signed local test event.</p></article></section><section class="card"><p class="eyebrow">Submission proof</p><h2>Why this is a business, not a chatbot</h2><div class="proof-grid"><div><strong>Earns</strong><p>Paid daily brief checkout event.</p></div><div><strong>Spends</strong><p>Model, search, and hosting costs debited under safety limits.</p></div><div><strong>Runs ops</strong><p>Repeatable scout/synthesis/render/delivery cycle.</p></div></div></section></main><footer>Built with Hermes Agent + MoA for the Nous Research x NVIDIA x Stripe hackathon.</footer><script src="app.js"></script></body></html>"""
STYLES = """:root{--bg:#090b10;--panel:#11141b;--text:#e8edf6;--muted:#8993a6;--line:rgba(255,255,255,.1);--gold:#ffc857;--green:#93d18b;--red:#ff6b6b;--blue:#8ab4ff}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at top left,#162033,#090b10 38%);color:var(--text);font-family:ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;line-height:1.45}.topbar{display:flex;justify-content:space-between;align-items:center;padding:28px 34px;border-bottom:1px solid var(--line);position:sticky;top:0;background:rgba(9,11,16,.86);backdrop-filter:blur(14px);z-index:10}h1,h2,h3,p{margin:0}h1{font-size:22px;letter-spacing:.08em;text-transform:uppercase}h2{font-size:30px;line-height:1.05;margin-top:8px}h3{font-size:18px;margin:6px 0 8px}.eyebrow{font-size:11px;text-transform:uppercase;letter-spacing:.18em;color:var(--gold);font-weight:700}.status-pill{border:1px solid var(--line);padding:8px 12px;border-radius:999px;color:var(--green);background:rgba(147,209,139,.08);font-size:13px}main{max-width:1180px;margin:0 auto;padding:28px 22px 48px}.card{background:linear-gradient(180deg,rgba(255,255,255,.055),rgba(255,255,255,.025));border:1px solid var(--line);border-radius:18px;padding:24px;box-shadow:0 24px 80px rgba(0,0,0,.28)}.hero{display:grid;grid-template-columns:1.5fr .8fr;gap:28px;align-items:center}.lede{font-size:18px;color:#c6cedb;margin:18px 0 0;max-width:760px}.cta-row{display:flex;gap:12px;margin-top:24px;flex-wrap:wrap}button{border:0;border-radius:12px;background:var(--gold);color:#15110a;font-weight:800;padding:13px 16px;cursor:pointer}button.secondary{background:transparent;color:var(--text);border:1px solid var(--line)}.hero-metrics{display:grid;gap:14px}.hero-metrics div{background:rgba(0,0,0,.22);border:1px solid var(--line);border-radius:16px;padding:18px}.hero-metrics span{display:block;font-size:30px;font-weight:800;color:var(--green)}label{display:block;color:var(--muted);font-size:12px;text-transform:uppercase;letter-spacing:.12em;margin-top:4px}.grid{display:grid;gap:18px;margin-top:18px}.three{grid-template-columns:repeat(3,1fr)}.two{grid-template-columns:repeat(2,1fr)}.section-head{display:flex;justify-content:space-between;gap:18px;align-items:end;margin-bottom:18px}.muted,.small{color:var(--muted)}.small{font-size:13px;margin-top:12px}.signals{display:grid;grid-template-columns:repeat(2,1fr);gap:14px}.signal{background:#171b24;border:1px solid var(--line);border-radius:14px;padding:16px}.signal .value{font-size:21px;color:var(--blue);font-weight:800;margin:8px 0}.signal .move{font-size:13px;color:var(--muted);margin-bottom:10px}.signal a{color:var(--gold)}ol{padding-left:22px}li{margin:10px 0}.roles,.safety{display:grid;gap:10px}.role,.limit{display:flex;justify-content:space-between;gap:16px;border-bottom:1px solid var(--line);padding:10px 0}.role code{color:var(--green)}.ledger{display:grid;gap:8px}.entry{display:grid;grid-template-columns:1fr auto;border-bottom:1px solid var(--line);padding:10px 0}.entry .amt{font-weight:800}.entry.revenue .amt{color:var(--green)}.entry.spend .amt,.entry.reserve .amt{color:var(--red)}.proof-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-top:14px}.proof-grid div{background:rgba(255,255,255,.04);border:1px solid var(--line);border-radius:14px;padding:16px}footer{color:var(--muted);padding:28px;text-align:center;border-top:1px solid var(--line)}@media(max-width:820px){.topbar{padding:20px;align-items:flex-start;gap:12px;flex-direction:column}.hero,.three,.two,.signals,.proof-grid{grid-template-columns:1fr}h2{font-size:25px}}"""
APP = """function money(c){var s=c<0?'-':'';return s+'$'+(Math.abs(c)/100).toFixed(2)}function pct(n){return Math.round(n*100)+'%'}function el(id){return document.getElementById(id)}function boot(){fetch('data.json').then(function(r){return r.json()}).then(function(data){var b=data.brief,l=data.ledger;el('headline').textContent=b.headline;el('abstract').textContent=b.abstract;el('price').textContent=data.format.price;el('balance').textContent=data.format.balance;el('confidence').textContent=pct(b.confidence||0);el('generatedAt').textContent='Generated '+b.generated_at;var mode=l.payment.mode.replaceAll('_',' ');el('paymentMode').textContent=mode;el('buyButton').onclick=function(){if(l.payment.payment_link){window.open(l.payment.payment_link,'_blank')}else{alert('Demo checkout event already generated: '+l.stripe_event.id+'\\nMode: '+mode)}};el('runButton').onclick=function(){alert('In the repo this runs: python3 scripts/run_full_cycle.py')};var sig=el('signals');sig.innerHTML='';b.signals.forEach(function(s){var d=document.createElement('div');d.className='signal';d.innerHTML='<h3>'+s.name+'</h3><div class="value">'+s.value+'</div><div class="move">'+s.movement+'</div><p>'+s.implication+'</p><p class="small">Source: <a href="'+s.url+'" target="_blank">'+s.source+'</a></p>';sig.appendChild(d)});var play=el('operatorPlay');play.innerHTML='';b.operator_play.forEach(function(x){var li=document.createElement('li');li.textContent=x;play.appendChild(li)});var roles=el('moaRoles');roles.innerHTML='';Object.keys(b.moa_roles).forEach(function(k){var d=document.createElement('div');d.className='role';d.innerHTML='<span>'+k+'</span><code>'+b.moa_roles[k]+'</code>';roles.appendChild(d)});var led=el('ledger');led.innerHTML='';l.entries.forEach(function(e){var d=document.createElement('div');d.className='entry '+e.type;d.innerHTML='<span>'+e.label+'<br><small class="muted">'+e.timestamp+'</small></span><span class="amt">'+money(e.amount_cents)+'</span>';led.appendChild(d)});var saf=el('safety');saf.innerHTML='';Object.keys(l.safety_limits).forEach(function(k){var d=document.createElement('div');d.className='limit';d.innerHTML='<span>'+k.replaceAll('_',' ')+'</span><strong>'+l.safety_limits[k]+'</strong>';saf.appendChild(d)})}).catch(function(err){document.body.innerHTML='<pre style="padding:24px;color:#fff">Failed to load demo data: '+err+'</pre>'})}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',boot)}else{boot()}"""
if __name__=='__main__': main()
